"use strict";

var ESHEEP_VERSION = "0.9.5";
var DEFAULT_XML = "https://cdn.jplopsoft.idv.tw/images/esheep_animations.xml";
var COLLISION_TAGS = ["div", "hr"];

function bindEvent(element, eventName, handler) {
    if (element.addEventListener) element.addEventListener(eventName, handler, false);
    else if (element.attachEvent) element.attachEvent("on" + eventName, handler);
    else element["on" + eventName] = handler;
}

function getNodeText(node) {
    return node ? (node.textContent || node.text || "") : "";
}

function preventDefaultAction(event) {
    var e = event || window.event;
    if (e.preventDefault) e.preventDefault();
    else e.returnValue = false;
    return false;
}

var WebESheep = function (options, isChildAnimation) {
    this.options = options || { allowPopup: "yes" };
    this.animationFile = DEFAULT_XML;
    this.id = "esheep_" + new Date().getTime() + "_" + Math.floor(Math.random() * 1000);
    
    this.containerNode = document.createElement("div");
    this.containerNode.setAttribute("id", this.id);
    this.spriteImage = document.createElement("img");
    this.infoBox = document.createElement("div");

    this.xmlDoc = null;
    this.isDying = false; 
    this.isChild = isChildAnimation != null; 
    
    this.tilesX = 1; this.tilesY = 1;
    this.frameWidth = 1; this.frameHeight = 1;
    this.posX = 1; this.posY = 1;
    this.isFlipped = false; this.isDragging = false; this.isInfoBoxOpen = false;
    
    this.currentAnimationId = 0; this.currentStep = 0; this.currentAnimationNode = null;
    
    // --- 【修改 1】加入動作變異狀態屬性 ---
    // 0: 原版, 1: 倒退(太空漫步), 2: 狂暴(快轉), 3: 遲緩(慢動作)
    this.currentVariant = 0; 
    
    this.spritePreloader = new Image();
    this.collisionElement = null;
    this.randomSeed = 100 * Math.random();
    
    this.screenWidth = window.innerWidth || document.documentElement.clientWidth || document.body.clientWidth;
    this.screenHeight = window.innerHeight || document.documentElement.clientHeight || document.body.clientHeight;
};

WebESheep.prototype = {
    start: function () {
        var self = this;
        var xhr = window.XMLHttpRequest ? new XMLHttpRequest() : new ActiveXObject("Microsoft.XMLHTTP");
        
        xhr.open("GET", this.animationFile, true);
        xhr.onreadystatechange = function () {
            if (xhr.readyState === 4 && ((xhr.status >= 200 && xhr.status < 300) || xhr.status === 0)) {
                if (xhr.responseText) self._parseXMLData(xhr.responseText);
            }
        };
        xhr.send(null);
    },

    remove: function () {
        this.isDying = true;
        if(this.infoBox.hide) this.infoBox.hide();
        var el = document.getElementById(this.id);
        if (el && el.parentNode) el.parentNode.removeChild(el);
    },

    _parseXMLData: function (xmlString) {
        var self = this;
        if (window.DOMParser) {
            this.xmlDoc = new DOMParser().parseFromString(xmlString, "text/xml");
        } else {
            this.xmlDoc = new ActiveXObject("Microsoft.XMLDOM");
            this.xmlDoc.async = false;
            this.xmlDoc.loadXML(xmlString);
        }

        var imageNode = this.xmlDoc.getElementsByTagName("image")[0];
        if (!imageNode) return;

        this.tilesX = Math.max(1, parseInt(getNodeText(imageNode.getElementsByTagName("tilesx")[0]), 10) || 1);
        this.tilesY = Math.max(1, parseInt(getNodeText(imageNode.getElementsByTagName("tilesy")[0]), 10) || 1);

        bindEvent(this.spritePreloader, "load", function () {
            // 【修正】加入 naturalWidth 保障 IE 取值
            var rawWidth = self.spritePreloader.naturalWidth || self.spritePreloader.width || 200;
            var rawHeight = self.spritePreloader.naturalHeight || self.spritePreloader.height || 200;

            self.frameWidth = Math.max(1, rawWidth / self.tilesX);
            self.frameHeight = Math.max(1, rawHeight / self.tilesY);

            // ----------------------------------------------------
            // 👇 替換成下面這三行 👇
            // ----------------------------------------------------
            self.spriteImage.style.cssText = "width:" + rawWidth + "px !important; height:" + rawHeight + "px !important; position:absolute !important; max-width:none !important; display:block !important;";
            self.spriteImage.style.top = "0px";
            self.spriteImage.style.left = "0px";

            self.containerNode.style.cssText = "width:" + self.frameWidth + "px !important; height:" + self.frameHeight + "px !important; position:fixed !important; cursor:move !important; z-index:999999 !important; overflow:hidden !important; display:block !important; pointer-events:auto !important;";
            
            if(!self.isChild) {
                self.posX = self.screenWidth / 2;
                self.posY = 0; 
                self.containerNode.style.left = self.posX + "px";
                self.containerNode.style.top = self.posY + "px";
            }

            bindEvent(self.spriteImage, "dragstart", preventDefaultAction);
            self.containerNode.appendChild(self.spriteImage);
            document.body.appendChild(self.containerNode);

            if (self.isChild) self._spawnChild();
            else self._spawnESheep();
        });

        var base64Data = getNodeText(imageNode.getElementsByTagName("png")[0]).replace(/\s/g, '');
        this.spritePreloader.src = "data:image/png;base64," + base64Data;
        this.spriteImage.setAttribute("src", this.spritePreloader.src);

        this._bindMouseEvents();
    },

    _bindMouseEvents: function () {
        var self = this;
        bindEvent(this.containerNode, "mousedown", function () {
            self.isDragging = true; self.collisionElement = null;
            self.currentVariant = 0; 
            var animNodes = self.xmlDoc.getElementsByTagName("animations")[0].getElementsByTagName("animation");
            for (var n = 0; n < animNodes.length; n++) {
                if (getNodeText(animNodes[n].getElementsByTagName("name")[0]) === "drag") {
                    self.currentAnimationId = animNodes[n].getAttribute("id");
                    self.currentStep = 0; self.currentAnimationNode = animNodes[n];
                    break;
                }
            }
        });

        bindEvent(document.documentElement, "mousemove", function (event) {
            if (!self.isDragging) return;
            var e = event || window.event;
            self.posX = parseInt(e.clientX) - self.frameWidth / 2;
            self.posY = parseInt(e.clientY) - self.frameHeight / 2;
            self.containerNode.style.left = self.posX + "px";
            self.containerNode.style.top = self.posY + "px";
        });

        bindEvent(document.documentElement, "mouseup", function () {
            if (self.isDragging) self.isDragging = false;
        });

        bindEvent(window, "resize", function () {
            self.screenWidth = window.innerWidth || document.documentElement.clientWidth || document.body.clientWidth;
            self.screenHeight = window.innerHeight || document.documentElement.clientHeight || document.body.clientHeight;
        });
    },

    _setPosition: function (deltaX, deltaY, isAbsolute) {
        if (!this.containerNode) return;
        // 【修正】使用 Math.round 讓移動更滑順，避免 IE 解析字串座標報錯
        this.posX = isAbsolute ? Math.round(deltaX) : Math.round(this.posX) + Math.round(deltaX);
        this.posY = isAbsolute ? Math.round(deltaY) : Math.round(this.posY) + Math.round(deltaY);
        
        if (!isNaN(this.posX)) this.containerNode.style.left = this.posX + "px";
        if (!isNaN(this.posY)) this.containerNode.style.top = this.posY + "px";
    },

    _evaluateExpression: function (expressionStr) {
        if (!expressionStr || typeof expressionStr !== "string") return 0;
        var val = expressionStr.replace(/screenW/g, this.screenWidth)
                               .replace(/screenH/g, this.screenHeight)
                               .replace(/areaW/g, this.screenWidth)
                               .replace(/areaH/g, this.screenHeight)
                               .replace(/imageW/g, this.frameWidth)
                               .replace(/imageH/g, this.frameHeight)
                               .replace(/random/g, "(100 * Math.random())")
                               .replace(/randS/g, this.randomSeed)
                               .replace(/imageX/g, this.posX)
                               .replace(/imageY/g, this.posY);
        try {
            var result = new Function("return " + val)(); 
            return isNaN(result) ? 0 : Number(result);
        } catch (e) {
            return 0;
        }
    },

    _spawnESheep: function () {
        var spawnNodes = this.xmlDoc.getElementsByTagName("spawns")[0].getElementsByTagName("spawn");
        var targetIndex = Math.floor(Math.random() * spawnNodes.length);
        var node = spawnNodes[targetIndex];
        
        var startX = this._evaluateExpression(getNodeText(node.getElementsByTagName("x")[0]));
        var startY = this._evaluateExpression(getNodeText(node.getElementsByTagName("y")[0]));
        
        if (!isNaN(startX)) this.posX = startX;
        if (!isNaN(startY)) this.posY = startY;

        this._setPosition(this.posX, this.posY, true);
        this.currentAnimationId = getNodeText(node.getElementsByTagName("next")[0]);
        this.currentStep = 0;
        this.currentVariant = Math.floor(Math.random() * 4); 

        var animNodes = this.xmlDoc.getElementsByTagName("animations")[0].getElementsByTagName("animation");
        for (var s = 0; s < animNodes.length; s++) {
            if (animNodes[s].getAttribute("id") === this.currentAnimationId) {
                this.currentAnimationNode = animNodes[s];
                break;
            }
        }
        this._runAnimationStep();
    },

    _spawnChild: function () {
        var animNodes = this.xmlDoc.getElementsByTagName("animations")[0].getElementsByTagName("animation");
        for (var t = 0; t < animNodes.length; t++) {
            if (animNodes[t].getAttribute("id") === this.currentAnimationId) {
                this.currentAnimationNode = animNodes[t];
                break;
            }
        }
        this.currentVariant = Math.floor(Math.random() * 4); 
        this._runAnimationStep();
    },

    _getNextRandomNode: function (parentNode) {
        if (!parentNode) return false;
        var nextNodes = parentNode.getElementsByTagName("next");
        if (nextNodes.length === 0) {
            if (this.isChild) { this.remove(); return false; } 
            else { this._spawnESheep(); return false; }
        }

        var animNodes = this.xmlDoc.getElementsByTagName("animations")[0].getElementsByTagName("animation");
        var nextAnimId = getNodeText(nextNodes[Math.floor(Math.random() * nextNodes.length)]); 
        
        var foundNext = false;
        for (var n = 0; n < animNodes.length; n++) {
            if (animNodes[n].getAttribute("id") === nextAnimId) {
                this.currentAnimationId = animNodes[n].getAttribute("id");
                this.currentStep = 0;
                this.currentAnimationNode = animNodes[n];
                this.currentVariant = Math.floor(Math.random() * 4); 
                foundNext = true;
                break;
            }
        }
        return foundNext;
    },

    _checkCollision: function () {
        var hitPadding = this.collisionElement ? 5 : 20;
        var bottomEdgeY = this.posY + this.frameHeight;

        for (var i = 0; i < COLLISION_TAGS.length; i++) {
            var elements = document.body.getElementsByTagName(COLLISION_TAGS[i]);
            for (var o = 0; o < elements.length; o++) {
                var bounds = elements[o].getBoundingClientRect();
                if (bottomEdgeY > bounds.top - 2 && bottomEdgeY < bounds.top + hitPadding && 
                    this.posX > bounds.left && this.posX < bounds.right - this.frameWidth) {
                    
                    var computedStyle = window.getComputedStyle ? window.getComputedStyle(elements[o]) : elements[o].currentStyle;
                    if (computedStyle && computedStyle.borderTopStyle !== "none" && computedStyle.display !== "none") {
                        return elements[o];
                    }
                }
            }
        }
        return false;
    },

    _getXmlValue: function (parentTagName, childTagName, defaultValue) {
        if (this.currentAnimationNode && this.currentAnimationNode.getElementsByTagName(parentTagName)[0]) {
            var childNode = this.currentAnimationNode.getElementsByTagName(parentTagName)[0].getElementsByTagName(childTagName)[0];
            if (childNode) return this._evaluateExpression(getNodeText(childNode));
        }
        return defaultValue;
    },

    _runAnimationStep: function () {
        if (this.isDying || !this.currentAnimationNode) return;

        var startX = this._getXmlValue("start", "x", 0);
        var startY = this._getXmlValue("start", "y", 0);
        var startInterval = this._getXmlValue("start", "interval", 1000);
        var endX = this._getXmlValue("end", "x", 0);
        var endY = this._getXmlValue("end", "y", 0);
        var endInterval = this._getXmlValue("end", "interval", 1000);

        var seqNode = this.currentAnimationNode.getElementsByTagName("sequence")[0];
        var repeatCount = seqNode ? this._evaluateExpression(seqNode.getAttribute("repeat") || "0") : 0;
        var repeatFrom = seqNode ? parseInt(seqNode.getAttribute("repeatfrom") || "0") : 0;
        
        var frameNodes = this.currentAnimationNode.getElementsByTagName("frame");
        if(frameNodes.length === 0) { this._getNextRandomNode(seqNode); return; }

        var totalFrames = frameNodes.length + Math.max(0, (frameNodes.length - repeatFrom) * repeatCount);
        if(totalFrames <= 0) totalFrames = 1;

        // --- 【修改 2】核心邏輯：動態處理影格倒放 (太空漫步) ---
        var logicalStep = this.currentStep;
        if (this.currentVariant === 1) { 
            logicalStep = (totalFrames - 1) - this.currentStep;
            if (logicalStep < 0) logicalStep = 0; 
        }

        var currentFrameNode;
        if (logicalStep < frameNodes.length) {
            currentFrameNode = frameNodes[logicalStep];
        } else {
            var cycleLen = Math.max(1, frameNodes.length - repeatFrom);
            var remainder = (logicalStep - repeatFrom) % cycleLen;
            currentFrameNode = frameNodes[repeatFrom + remainder];
        }
        
        var currentFrameIndex = parseInt(getNodeText(currentFrameNode)) || 0;
        
        // 【修正】使用 Math.floor 確保精準算出整數格數，避免 IE 因為小數點錯位破圖
        var colIndex = currentFrameIndex % this.tilesX;
        var rowIndex = Math.floor(currentFrameIndex / this.tilesX);
        this.spriteImage.style.left = Math.floor(-this.frameWidth * colIndex) + "px";
        this.spriteImage.style.top = Math.floor(-this.frameHeight * rowIndex) + "px";

        if (this.isDragging) {
            this.currentStep++;
            setTimeout(this._runAnimationStep.bind(this), 50);
            return;
        }

        if (this.isFlipped) { startX = -startX; endX = -endX; }

        if (this.currentStep === 0) {
            this._setPosition(startX, startY, false);
        } else {
            var stepRatio = this.currentStep / totalFrames;
            // 【修正】這裡的運算也改用 Math.round 來取代 parseInt
            var dx = Math.round(startX + (endX - startX) * stepRatio);
            var dy = Math.round(startY + (endY - startY) * stepRatio);
            this._setPosition(dx, dy, false);
        }

        this.currentStep++;

        if (this.currentStep >= totalFrames) {
            var actionNode = this.currentAnimationNode.getElementsByTagName("action")[0];
            if (actionNode && getNodeText(actionNode) === "flip") {
                this.isFlipped = !this.isFlipped;
                
                // 【修正】改用 scaleX 來翻轉，並加入 -ms-transform 確保 IE10 穩定支援
                var scaleValue = this.isFlipped ? "scaleX(-1)" : "scaleX(1)";
                this.containerNode.style.transform = scaleValue;
                this.containerNode.style.msTransform = scaleValue;
                this.containerNode.style.webkitTransform = scaleValue;
            }
            if (!this._getNextRandomNode(seqNode)) return;
        }

        var isBorderTriggered = false;
        var borderNode = this.currentAnimationNode.getElementsByTagName("border");
        var gravityNode = this.currentAnimationNode.getElementsByTagName("gravity");

        if (borderNode && borderNode[0] && borderNode[0].getElementsByTagName("next").length > 0) {
            if (endX < 0 && this.posX < 0) {
                this.posX = 0; isBorderTriggered = true;
            } else if (endX > 0 && this.posX > this.screenWidth - this.frameWidth) {
                this.posX = this.screenWidth - this.frameWidth;
                this.containerNode.style.left = this.posX + "px";
                isBorderTriggered = true;
            } else if (endY < 0 && this.posY < 0) {
                this.posY = 0; isBorderTriggered = true;
            } else if (endY > 0 && this.posY > this.screenHeight - this.frameHeight) {
                this.posY = this.screenHeight - this.frameHeight;
                isBorderTriggered = true;
            } else if (endY > 0) {
                var collisionRes = this._checkCollision();
                if (collisionRes && this.posY > this.frameHeight) {
                    this.collisionElement = collisionRes;
                    this.posY = Math.ceil(this.collisionElement.getBoundingClientRect().top) - this.frameHeight;
                    isBorderTriggered = true;
                }
            } else if (this.collisionElement && !this._checkCollision()) {
                var elRect = this.collisionElement.getBoundingClientRect();
                if (this.posY + this.frameHeight > elRect.top + 3 || this.posY + this.frameHeight < elRect.top - 3) {
                    this.collisionElement = null;
                } else if (this.posX < elRect.left) {
                    this.posX = Math.round(this.posX + 3); isBorderTriggered = true;
                } else {
                    this.posX = Math.round(this.posX - 3); isBorderTriggered = true;
                }
                this.containerNode.style.left = this.posX + "px";
            }
            if (isBorderTriggered && !this._getNextRandomNode(borderNode[0])) return;
        }

        if (!isBorderTriggered && gravityNode && gravityNode[0] && gravityNode[0].getElementsByTagName("next").length > 0) {
            if (this.posY < this.screenHeight - this.frameHeight - 2) {
                if (this.collisionElement == null) {
                    isBorderTriggered = true;
                } else if (!this._checkCollision()) {
                    isBorderTriggered = true;
                    this.collisionElement = null;
                }
                if (isBorderTriggered && !this._getNextRandomNode(gravityNode[0])) return;
            }
        }

        if (!isBorderTriggered && (this.posX < -this.frameWidth || this.posX > this.screenWidth || this.posY < -this.frameHeight || this.posY > this.screenHeight)) {
            if (!this.isChild) this._spawnESheep();
            return;
        }

        // --- 【修改 3】核心邏輯：動態處理播放速度 (狂暴/遲緩) ---
        // 【修正】用 Math.floor 防止出現小數點 interval
        var currentInterval = Math.max(20, Math.floor(startInterval) + Math.floor((endInterval - startInterval) * (this.currentStep / totalFrames)));

        if (this.currentVariant === 2) {
            currentInterval = Math.max(10, Math.floor(currentInterval * 0.4)); 
        } else if (this.currentVariant === 3) {
            currentInterval = Math.floor(currentInterval * 2.5);               
        }

        var bindSelf = this;
        setTimeout(function() { bindSelf._runAnimationStep(); }, currentInterval || 50);
    }
};

if (!Function.prototype.bind) {
    Function.prototype.bind = function (oThis) {
        var aArgs = Array.prototype.slice.call(arguments, 1), fToBind = this, fNOP = function () {}, fBound = function () { return fToBind.apply(this instanceof fNOP ? this : oThis, aArgs.concat(Array.prototype.slice.call(arguments))); };
        if (this.prototype) fNOP.prototype = this.prototype; fBound.prototype = new fNOP(); return fBound;
    };
}